mapper.select:
		SELECT *
    	FROM
    	(
    		SELECT ROW_NUMBER() OVER(ORDER BY ${sidx} ${sord}) RowNo, a.*
    		FROM (
				SELECT e.*, u.usersRole FROM employee e INNER JOIN users u
				ON e.employeeId = u.usersId

			) a
		) b
    	WHERE b.RowNo between (1+(${page} - 1 ) * ${rows}) and (${page} * ${rows});

SELECT e.*, u.usersRole, u.pwdChangeYn, u.usersLockStatus FROM employee e INNER JOIN users u 
ON e.employeeId = u.usersId
WHERE e.employeeId = #{employeeId};

SELECT userAlarmsParameterSub 
FROM userAlarms 
WHERE userAlarmsEmployeeId = #{employeeId} 
AND userAlarmsState = 'R'
AND userAlarmsParameter = ${issueKeyNum}
AND userAlarmsParameterSub != 0
GROUP BY userAlarmsParameterSub;

mapper.update:
UPDATE userAlarms SET userAlarmsState = 'Y'
WHERE userAlarmsEmployeeId = #{employeeId} 
AND userAlarmsState = 'R'
AND userAlarmsParameter = ${issueKeyNum}
AND userAlarmsParameterSub != 0;
